// ─── Trading symbols we care about ───────────────────────────────────────────
const SYMBOLS = [
  {sym:'BTC',  keywords:['bitcoin','btc']},
  {sym:'ETH',  keywords:['ethereum','eth']},
  {sym:'BNB',  keywords:['bnb','binance coin']},
  {sym:'SOL',  keywords:['solana','sol']},
  {sym:'XRP',  keywords:['ripple','xrp']},
  {sym:'DOGE', keywords:['doge','dogecoin']},
  {sym:'ADA',  keywords:['cardano','ada']},
  {sym:'AVAX', keywords:['avalanche','avax']},
  {sym:'DOT',  keywords:['polkadot','dot']},
  {sym:'LINK', keywords:['chainlink','link']},
  {sym:'LTC',  keywords:['litecoin','ltc']},
  {sym:'ATOM', keywords:['cosmos','atom']},
  {sym:'UNI',  keywords:['uniswap','uni']},
  {sym:'INJ',  keywords:['injective','inj']},
  {sym:'APT',  keywords:['aptos','apt']},
  {sym:'ARB',  keywords:['arbitrum','arb']},
  {sym:'OP',   keywords:['optimism',' op ','optimistic']},
  {sym:'NEAR', keywords:['near protocol','near']},
  {sym:'FIL',  keywords:['filecoin','fil']},
  {sym:'ICP',  keywords:['internet computer','icp']},
];

// ─── Fetch news data ──────────────────────────────────────────────────────────
const cgNews = $('Fetch CoinGecko News1').isExecuted
  ? ($('Fetch CoinGecko News1').first()?.json?.articles || [])
  : [];
const rssItems = $('Fetch CryptoPanic RSS1').isExecuted
  ? $('Fetch CryptoPanic RSS1').all().map(i => i.json)
  : [];
const fundingData = $('Fetch Funding Rates1').isExecuted
  ? $('Fetch Funding Rates1').all().map(d => d.json)
  : [];
const liquidations = $('Fetch Liquidations1').isExecuted
  ? $('Fetch Liquidations1').all().map(d => d.json)
  : [];

const timestamp = new Date().toISOString();

// ─── Build headline pool ──────────────────────────────────────────────────────
const allHeadlines = [
  ...rssItems.slice(0,30).map(i => ({title: i.title||'', source:'CryptoPanic', pubDate: i.pubDate||''})),
  ...cgNews.slice(0,30).map(a  => ({title: a.title||'', source:'CoinGecko',    pubDate: a.publishedAt||''})),
];

// ─── Funding rate lookup (symbol -> rate) ─────────────────────────────────────
const fundingMap = {};
fundingData.forEach(d => {
  if(d.symbol) {
    const base = d.symbol.replace('USDT','').replace('USDC','');
    fundingMap[base] = parseFloat(d.lastFundingRate || 0);
  }
});

// ─── Global market sentiment from funding ────────────────────────────────────
const rates = Object.values(fundingMap);
const avgFunding = rates.length > 0 ? rates.reduce((s,r)=>s+r,0)/rates.length : 0;
const fundingSentiment = avgFunding > 0.001 ? 'BULLISH_EXTREME'
  : avgFunding < -0.001 ? 'BEARISH_EXTREME'
  : avgFunding > 0 ? 'BULLISH' : avgFunding < 0 ? 'BEARISH' : 'NEUTRAL';

// ─── Liquidation bias ─────────────────────────────────────────────────────────
const longLiqs  = liquidations.filter(d => d.side === 'SELL').length;
const shortLiqs = liquidations.filter(d => d.side === 'BUY').length;
const liqBias   = longLiqs > shortLiqs ? 'LONGS_SQUEEZED'
  : shortLiqs > longLiqs ? 'SHORTS_SQUEEZED' : 'BALANCED';

// ─── Build one item per coin ──────────────────────────────────────────────────
const results = [];
for (const {sym, keywords} of SYMBOLS) {
  // Filter headlines mentioning this coin
  const coinHeadlines = allHeadlines.filter(h => {
    const t = h.title.toLowerCase();
    return keywords.some(kw => t.includes(kw));
  });

  // Simple keyword sentiment for pre-scoring
  const bullWords = ['surge','pump','breakout','rally','ath','bull','gains','record','rise','moon','bullish','up','positive','launch','partnership','adoption','upgrade'];
  const bearWords = ['crash','drop','dump','bear','correction','sell','fear','panic','decline','plunge','bearish','down','negative','hack','exploit','ban','lawsuit','sec'];
  const coinText  = coinHeadlines.map(h=>h.title).join(' ').toLowerCase();
  const bullScore = bullWords.filter(w => coinText.includes(w)).length;
  const bearScore = bearWords.filter(w => coinText.includes(w)).length;

  const coinFundingRate = fundingMap[sym] || 0;
  const coinFundingBias = coinFundingRate > 0.001 ? 'BULLISH_EXTREME'
    : coinFundingRate < -0.001 ? 'BEARISH_EXTREME'
    : coinFundingRate > 0 ? 'BULLISH' : coinFundingRate < 0 ? 'BEARISH' : 'NEUTRAL';

  results.push({
    json: {
      id:              `${sym}_${Date.now()}`,
      symbol:          `${sym}USDT`,
      symbols:         [sym],
      source:          'n8n-sentiment-feed',
      published_at:    Math.floor(Date.now()/1000),
      title:           coinHeadlines.length > 0
                         ? coinHeadlines.map(h=>h.title).join(' | ').slice(0,400)
                         : `No specific ${sym} news. Market is ${fundingSentiment}.`,
      headline_count:  coinHeadlines.length,
      bull_score:      bullScore,
      bear_score:      bearScore,
      pre_direction:   bullScore > bearScore ? 'BULLISH'
                         : bearScore > bullScore ? 'BEARISH' : 'NEUTRAL',
      coin_funding_rate: coinFundingRate,
      coin_funding_bias: coinFundingBias,
      market_funding_sentiment: fundingSentiment,
      liquidation_bias: liqBias,
      avg_market_funding: Number(avgFunding.toFixed(6)),
      skip: false
    }
  });
}

return results;

const sentiment = $input.first().json;
const output = sentiment.output ? JSON.parse(sentiment.output) : sentiment;

const emoji = output.bias === 'BUY' ? '🟢' : output.bias === 'SELL' ? '🔴' : '🟡';
const moodEmoji = output.marketMood === 'RISK_ON' ? '🚀' : output.marketMood === 'RISK_OFF' ? '⚠️' : '😐';

const msg = `${emoji} <b>Market Sentiment Update</b> ${moodEmoji}

` +
  `📊 <b>Market Mood:</b> ${output.marketMood || 'N/A'}
` +
  `🎯 <b>Bias:</b> ${output.bias || 'N/A'} (${output.confidence || 0}% confidence)
` +
  `
💡 <b>Recommendation:</b>
${output.tradingRecommendation || 'No recommendation'}
` +
  `
🔑 <b>Key Narratives:</b>
${(output.keyNarratives || []).map(n => `• ${n}`).join('\n')}
` +
  `
⚠️ <b>Risks:</b>
${(output.topRisks || []).map(r => `• ${r}`).join('\n')}
` +
  `
⏰ ${new Date().toISOString().replace('T', ' ').slice(0, 16)} UTC`;

return [{ json: { message: msg, parse_mode: 'HTML' } }];

// Parse AI output
const raw = String($json.output || $json.text || '{}');
const txt = raw.replace(/```json?/gi, '').replace(/```/g, '').trim();

const si = txt.indexOf('{');
const ei = txt.lastIndexOf('}');
let p = {};
try {
  if (si > -1 && ei > si) p = JSON.parse(txt.slice(si, ei + 1));
} catch (err) {
  console.warn('[Sentiment] JSON parse failed:', err.message);
}

const score  = Math.max(-1, Math.min(1, parseFloat(p.sentiment_score) || 0));
const impact = Math.max(0,  Math.min(1, parseFloat(p.impact_score)    || 0.5));
const conf   = Math.max(0,  Math.min(1, parseFloat(p.confidence)      || 0.5));
const dir    = (String(p.direction || 'NEUTRAL').replace(/[^A-Z]/g, '').toUpperCase() || 'NEUTRAL');

// ✅ Pull the original coin item from BEFORE the AI node
const originalItem = $('Skip Empty').item.json;

// ✅ Derive symbol from original item (e.g. "BTCUSDT" → "BTC")
const coinSym = String(
  (originalItem.symbol || '').replace(/USDT|USDC/gi, '') ||
  (Array.isArray(originalItem.symbols) ? originalItem.symbols[0] : '') ||
  ''
).toUpperCase().trim();

// InfluxDB line protocol escaping
const BS = String.fromCharCode(92);
const escTag = function(v) {
  let s = String(v == null ? '' : v);
  s = s.split(BS).join(BS + BS);
  s = s.split(',').join(BS + ',');
  s = s.split('=').join(BS + '=');
  s = s.split(' ').join(BS + ' ');
  return s;
};
const escField = function(v) {
  let s = String(v == null ? '' : v);
  s = s.split(BS).join(BS + BS);
  s = s.split('"').join(BS + '"');
  s = s.split('\n').join(' ');
  return s;
};

const src   = escTag(originalItem.source || $json.source || 'news');
const aid   = escField(originalItem.id   || 'unknown');
const title = escField(originalItem.title || $json.headline || '');
const ts    = (parseInt(originalItem.published_at) || Math.floor(Date.now() / 1000)) * 1000000000;

// Build symbol list — prefer coin sym, fallback to symbols array, then CRYPTO
let syms = [];
if (coinSym && coinSym.length > 0 && coinSym !== 'UNDEFINED') {
  syms = [coinSym];
} else if (Array.isArray(originalItem.symbols) && originalItem.symbols.length > 0) {
  syms = originalItem.symbols
    .map(function(x) { return typeof x === 'object' ? String(x.symbol || x.name || 'CRYPTO') : String(x); })
    .filter(function(x) { return x && x.trim().length > 0; });
} else if (typeof originalItem.symbols === 'string' && originalItem.symbols.trim()) {
  syms = [originalItem.symbols.trim()];
} else {
  syms = ['CRYPTO'];
}

// Build InfluxDB line protocol
const lp = syms.map(function(sym) {
  return 'news_sentiment,symbol=' + escTag(sym) + ',source=' + src + ',direction=' + escTag(dir)
    + ' sentiment_score=' + score + ',impact_score=' + impact + ',confidence=' + conf
    + ',article_id="' + aid + '",title="' + title + '" ' + ts;
}).join('\n');

// ✅ Return plain object (not an array) — required for "Run Once for Each Item" mode
return {
  json: {
    lineProtocol: lp,
    symbol: syms[0],
    count: syms.length,
    direction: dir,
    sentiment_score: score,
    confidence: conf
  }
};

const items = $input.all();
console.log(`[Sentiment] InfluxDB write completed for ${items.length} item(s)`);
return items.map(item => ({ json: { success: true, status: item.json?.status ?? 204 } }));

// Finalize X batches (emit combined)
const mem = $getWorkflowStaticData('global')
const all = Array.isArray(mem.x_items) ? mem.x_items : []
// Emit as normal n8n items:
return all.map(j => ({ json: j }))

const mem = $getWorkflowStaticData('global');

// all RSS items produced for this batch
const batch = $input.all().map(i => i.json);

// append to the accumulator
mem.x_items = (mem.x_items ?? []).concat(batch);

// read the metadata written by “Set batch metadata”
const batchIndex  = Number(mem.batchIndex ?? 0);
const batchCount  = Number(mem.batchCount ?? 0);
const hasMore     = batchIndex < (batchCount - 1);

// emit a single control item that drives the IF node
return [{
  json: {
    added: batch.length,
    total: mem.x_items.length,
    batchIndex,
    batchCount,
    hasMore,
  },
}];

// Code - Tag topic (place right after RSS Read)
const topic = String(
  $json.topic                                   // if present
  ?? $item(0).$node["Init RunConfig1"].json.topic // from the config node
  ?? 'crypto'
).toLowerCase();

return $input.all().map(i => ({ json: { ...i.json, topic } }));

