const topic = String(
  $json.topic                                   // if present
  ?? $item(0).$node["Init RunConfig1"].json.topic // from the config node
  ?? 'crypto'
).toLowerCase();

return $input.all().map(i => ({ json: { ...i.json, topic } }));

// Sanitize raw XML — fixes "Invalid character in entity name" from unescaped & in URLs
// Use this node between an HTTP Request (raw fetch) and an XML parser.
// Wire: HTTP Request (responseFormat: text) → this node → XML node
const raw = String($json.data || $json.body || $json.content || '')
if (!raw) return $input.all()

// Escape bare & that are not already valid XML entities
const sanitized = raw.replace(
  /&(?!(?:amp|lt|gt|quot|apos|#\d+|#x[\da-fA-F]+);)/g,
  '&amp;'
)
return [{ json: { ...$json, sanitizedXml: sanitized } }]
